import SwiftUI

struct SessionExpiredView: View { @Environment(AuthenticationStore.self) private var store; var body: some View { ZStack { BotaplataColors.background.ignoresSafeArea(); BotaplataCard { VStack(alignment: .leading, spacing: BotaplataSpacing.md) { Text("Votre session a expiré.").font(.title.bold()); Text("Connectez-vous de nouveau pour accéder aux dernières données Botaplata.").foregroundStyle(BotaplataColors.textSecondary); Button("Se reconnecter") { Task { await store.logout() } }.buttonStyle(.borderedProminent).accessibilityIdentifier("sessionExpired.relogin") } }.padding() } } }
